class Node:
    def __init__(self, val=None, children=None):
        self.val = val
        self.children = children if children is not None else []

class Codec:
    def serialize(self, root):
        if root is None:
            return ""

        data = str(root.val) + " "
        for child in root.children:
            data += self.serialize(child)
        data += "# "
        return data

    def deserialize(self, data):
        def dfs(iter_data):
            val = next(iter_data)
            if val == "#":
                return None

            node = Node(int(val))
            while True:
                child = dfs(iter_data)
                if child is None:
                    break
                node.children.append(child)
            return node

        return dfs(iter(data.split()))

```

    1. To serialize, perform a pre-order traversal of the tree, and store the node value followed by a space, form the string step by step.
2. Append '#' followed by a space for indicating end of each internal node.
3. To deserialize, split the serialized string into tokens, and create an iterator.
4. Call the recursive deserialize helper function with the iterator as the argument.
5. In deserialize helper function, keep track of children and separate them from parent nodes by checking for the end-of-node indicator '#'.

