class Node {
    constructor(val, children = []) {
        this.val = val;
        this.children = children;
    }
}

class Codec {
    serialize(root) {
        if (!root) return "";
        let data = root.val + " ";
        for (const child of root.children) {
            data += this.serialize(child);
        }
        data += "# ";
        return data;
    }

    deserialize(data) {
        const tokens = data.split(" ");
        tokens.pop();
        const iter = tokens[Symbol.iterator]();
        return this.deserializeHelper(iter);
    }

    deserializeHelper(iter) {
        const token = iter.next().value;
        if (token === "#") return null;
        const node = new Node(parseInt(token));
        while (true) {
            const child = this.deserializeHelper(iter);
            if (child === null) break;
            node.children.push(child);
        }
        return node;
    }
}

